"""

# 优化后的标题检测算法
def detect_heading(text):
    """多级标题识别系统"""
    text = text.strip()

    # 层级判断规则
    rules = [
        (r'^(第[一二三四五六七八九十]+章)\s+', 'h1'),      # 章级标题
        (r'^\d+\.\d+\s+', 'h2'),                        # 数字子标题
        (r'^（[一二三四五六七八九十]+）', 'h2'),            # 括号中文编号
        (r'^[A-Za-z]\.\s+', 'h3'),                      # 字母编号
        (r'^▶|➤|●', 'h3'),                              # 特殊符号开头
        (r'[:：]$', 'h3')                               # 冒号结尾
    ]

    for pattern, level in rules:
        if re.search(pattern, text):
            return level
    return None

# 升级版HTML生成器
def generate_pro_html(title, content, url):
    """生成出版级HTML文档"""
    html_template = f"""
    <!DOCTYPE html>
    <html>
    <head>
        <meta charset="UTF-8">
        <title>{title}</title>
        <style>{CSS_STYLE}</style>
    </head>
    <body>
        <h1>{title}</h1>
        <div class="meta-info">
            来源：微信公众平台<br>
            原文链接：<a href="{url}">{url}</a>
        </div>
        <article>
    """

    current_tag = 'p'
    for line in content.split('\n'):
        line = line.strip()
        if not line:
            continue

        heading_level = detect_heading(line)

        if heading_level:
            # 闭合之前的标签
            if current_tag != 'p':
                html_template += f"</{current_tag}>"
            html_template += f"<{heading_level}>{line}</{heading_level}>"
            current_tag = heading_level
        else:
            if current_tag != 'p':
                html_template += f"<p>{line}</p>"
            else:
                html_template += f"{line}<br>"

    html_template += """
        </article>
    </body>
    </html>
    """
    return html_template

# 优化后的PDF保存函数
def save_to_pdf(html_content, filename):
    """专业PDF生成配置"""
    options = {
        'encoding': "UTF-8",
        'quiet': '',
        'page-size': 'A4',
        'margin-top': '20mm',
        'margin-bottom': '25mm',
        'header-right': '[title]',
        'footer-center': '[page]/[topage]'
    }

    try:
        # 注意修改为你的wkhtmltopdf安装路径
        config = pdfkit.configuration(
            wkhtmltopdf=r'C:\Program Files\wkhtmltopdf\bin\wkhtmltopdf.exe'
        )

        # 自动创建目录
        desktop = get_desktop_path()
        Path(desktop).mkdir(parents=True, exist_ok=True)

        full_path = os.path.join(desktop, filename)
        pdfkit.from_string(html_content, full_path, options=options, configuration=config)
        return full_path
    except Exception as e:
        print(f"PDF生成失败：{str(e)}")
        return None

# 在main函数中使用：
if __name__ == "__main__":
    url = input("请输入微信文章链接：")
